            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プレミアムプランで上限に達した場合は unavailable を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // reached limit
