import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';

void main() {
  group('useFabState', () {
    const testUserId = 'test-user-id';
    const testTeamId = 'test-team-id';
    final fixedNow = DateTime.utc(2024, 6, 1);
    late DateTime activePlanStartDate;
    late DateTime activePlanEndDate;
    final testSession = Session(
      id: 'session-1',
      userId: testUserId,
      teamId: testTeamId,
    );

    final mockProfileStorage = FakeProfileStorage(
      userId: testUserId,
      teamId: testTeamId,
    );

    setUp(() {
      overrideTeamPlanNow(() => fixedNow);
      activePlanStartDate = fixedNow.subtract(const Duration(days: 30));
      activePlanEndDate = fixedNow.add(const Duration(days: 365));
    });

    tearDown(resetTeamPlanNow);

    testWidgets('録画が利用可能な場合は available を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 50,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プレミアムでなく解析できない場合は needsSubscription を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プランが期限切れの場合は needsSubscription を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 10,
          isActive: true,
          startDate: fixedNow.subtract(const Duration(days: 400)),
          endDate: fixedNow.subtract(const Duration(days: 1)),
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プレミアムプランで上限に達した場合は unavailable を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('プレミアムプランでボールが残っている場合は available を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 900, // approaching limit but not reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      // Premium だがボールが残っている場合は available になるべき
      expect(result, FabState.available);
