      expect(result, FabState.available);
    });

    testWidgets('プラン上限に達しているが Item にボールが残っている場合は available を返す',
        (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // plan limit reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // but item has remaining balls
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プランと Item の両方が上限に達している場合は needsSubscription を返す',
        (tester) async {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item,
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プランは上限に達しておらず Item が上限に達している場合は available を返す',
        (tester) async {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 20, // item exhausted
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 30, // plan has remaining balls (30 < 100)
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // total: usage=50, max=120, so 50 < 120 = available
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プランと Item の両方が上限に達しているかつプランがプレミアムの場合は unavailable を返す',
        (tester) async {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // plan limit reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // item also exhausted
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('Item のみがボールを提供する場合は available を返す', (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'free',
            maxBalls: 0, // no plan balls
            isPaid: false,
            isActive: true,
          ),
          currentUsage: 0,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item,
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });
  });
}

class _TestWidget extends HookConsumerWidget {
  const _TestWidget({
    required this.session,
    required this.teamId,
    required this.canSubscribe,
    required this.onResult,
  });

  final Session session;
  final String teamId;
  final bool canSubscribe;
  final void Function(FabState) onResult;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final state = useFabState(
      session: session,
      teamId: teamId,
      canSubscribe: canSubscribe,
    );

    onResult(state);

    return const SizedBox();
  }
}

