    test('ok: ちょうど 30 日後は ok (isBefore は等しい場合 false)', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          startDate: testNow,
          endDate: testNow.add(const Duration(days: 30)),
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.teamPlanStatus, TeamPlanStatus.ok);
    });

    test('ok: 31 日後なら ok', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          startDate: testNow,
          endDate: testNow.add(const Duration(days: 31)),
          currentUsage: 10,
          plan: testPlan,
        ),
      );
      expect(team.teamPlanStatus, TeamPlanStatus.ok);
    });

    test('ok: 使用量が 89% 未満なら ok', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          startDate: testNow,
          endDate: testNow.add(const Duration(days: 40)),
          currentUsage: 89,
          plan: const Plan(maxBalls: 100),
        ),
      );
      expect(team.teamPlanStatus, TeamPlanStatus.ok);
    });

    test('noContract: teamPlan が null なら noContract', () {
      final team = createTeam(teamPlan: null);
      expect(team.teamPlanStatus, TeamPlanStatus.noContract);
    });

