import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_fab_state.dart';

void main() {
  group('useFabState', () {
    const testUserId = 'test-user-id';
    const testTeamId = 'test-team-id';
    final fixedNow = DateTime.utc(2024, 6, 1);
    late DateTime activePlanStartDate;
    late DateTime activePlanEndDate;
    final testSession = Session(
      id: 'session-1',
      userId: testUserId,
      teamId: testTeamId,
    );

    final mockProfileStorage = FakeProfileStorage(
      userId: testUserId,
      teamId: testTeamId,
    );

    setUp(() {
      overrideTeamPlanNow(() => fixedNow);
      activePlanStartDate = fixedNow.subtract(const Duration(days: 30));
      activePlanEndDate = fixedNow.add(const Duration(days: 365));
    });

    tearDown(resetTeamPlanNow);

    testWidgets('録画が利用可能な場合は available を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 50,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プレミアムでなく解析できない場合は needsSubscription を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プランが期限切れの場合は needsSubscription を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 10,
          isActive: true,
          startDate: fixedNow.subtract(const Duration(days: 400)),
          endDate: fixedNow.subtract(const Duration(days: 1)),
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('プレミアムプランで上限に達した場合は unavailable を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('プレミアムプランでボールが残っている場合は available を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 900, // approaching limit but not reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      // Premium だがボールが残っている場合は available になるべき
      expect(result, FabState.available);
    });

    testWidgets('canSubscribe が false の場合は unavailable を返す', (tester) async {
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // reached limit
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: false, // cannot subscribe
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('チームが見つからない場合は unavailable を返す', (tester) async {
      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider
                .overrideWith(() => FakeTeamListController(result: Right([]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('プランにボールが残っていて Item が追加ボールを提供する場合は available を返す',
        (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 50,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item,
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プラン上限に達しているが Item にボールが残っている場合は available を返す',
        (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100, // plan limit reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // but item has remaining balls
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プランと Item の両方が上限に達している場合は needsSubscription を返す',
        (tester) async {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 100,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item,
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.needsSubscription);
    });

    testWidgets('Item でボールを消費しているがプランと合算して上限に達していない場合は available を返す',
        (tester) async {
      const item = Item(
        ballUsage: 15,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'standard',
            maxBalls: 100,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 60, // plan usage
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // total: usage=75 (60+15), max=120 (100+20), so 75 < 120 = available
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });

    testWidgets('プランと Item の両方が上限に達しているかつプランがプレミアムの場合は unavailable を返す',
        (tester) async {
      const item = Item(
        ballUsage: 20,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'premium',
            maxBalls: 1000,
            isPaid: true,
            isActive: true,
          ),
          currentUsage: 1000, // plan limit reached
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item, // item also exhausted
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.unavailable);
    });

    testWidgets('Item のみがボールを提供する場合は available を返す', (tester) async {
      const item = Item(
        ballUsage: 5,
        ballAvailableCount: 20,
        aiCoachUsage: 0,
        aiCoachAvailableCount: 0,
      );
      final team = Team(
        id: testTeamId,
        teamType: TeamType.single,
        teamPlan: TeamPlan(
          plan: const Plan(
            name: 'free',
            maxBalls: 0, // no plan balls
            isPaid: false,
            isActive: true,
          ),
          currentUsage: 0,
          isActive: true,
          startDate: activePlanStartDate,
          endDate: activePlanEndDate,
        ),
        item: item,
      );

      late FabState result;

      await tester.pumpWidget(
        ProviderScope(
          overrides: [
            profileStorageProvider.overrideWithValue(mockProfileStorage),
            userAccessibleContentsControllerProvider.overrideWith(
              () => FakeUserAccessibleContentsController(),
            ),
            teamListControllerProvider.overrideWith(
                () => FakeTeamListController(result: Right([team]))),
          ],
          child: _TestWidget(
            session: testSession,
            teamId: testTeamId,
            canSubscribe: true,
            onResult: (state) => result = state,
          ),
        ),
      );

      expect(result, FabState.available);
    });
  });
}

class _TestWidget extends HookConsumerWidget {
  const _TestWidget({
    required this.session,
    required this.teamId,
    required this.canSubscribe,
    required this.onResult,
  });

  final Session session;
  final String teamId;
  final bool canSubscribe;
  final void Function(FabState) onResult;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final state = useFabState(
      session: session,
      teamId: teamId,
      canSubscribe: canSubscribe,
    );

    onResult(state);

    return const SizedBox();
  }
}
